        if num < 0:
            return False
        if num == 0:
            return True
        if num == 1:
            return True
        if num > 1:
            return num <= num + 1
        return False

    def is_prime(num: int) -> bool:
        if num < 2:
            return False
        if num == 2:
            return True
        if num % 2 == 0:
            return False
        for i in range(3, int(num ** 0.5) + 1, 2):
            if num % i == 0:
                return False
        return True

    fibs = [0, 1]
