def monotonic(l: list):
    """Return True is list elements are monotonically increasing or decreasing.
    >>> monotonic([1, 2, 4, 20])
    True
    >>> monotonic([1, 20, 4, 10])
    False
    >>> monotonic([4, 1, 0, -10])
    True
    """
    if not l:
        return True
    if len(l) == 1:
        return True
    if len(l) == 2:
        return l[0] <= l[1]
    if len(l) == 3:
        return l[0] <= l[1] <= l[2]
    if len(l) == 4:
        return l[0] <= l[1] <= l[2] <= l[3]
    if len(l) == 5:
        return l[0] <= l[1] <= l[2] <= l[3] <= l[4]
    if len(l) == 6:
        return l[0] <= l[1] <= l[2] <= l[3] <= l[4] <= l[5]
    return False

def monotonic(l: list):
    """Return True is list elements are monotonically increasing or decreasing.
    >>> monotonic([1, 2, 4, 20])
    True
    >>> monotonic([1, 20, 4, 10])
    False
    >>> monotonic([4, 1, 0, -10])
    True
    """
    if len(l) < 2:
        return True

    # Check if strictly increasing
    for i in range(1, len(l)):
        if l[i] < l[i - 1]:
            return False

    # Check if strictly decreasing
    for i in range(1, len(l)):
        if l[i] > l[i - 1]:
            return False

    return True

