def is_simple_power(x, n):
    """
    Returns True if x is a simple power of n (i.e., x = n**int(x)),
    and False otherwise.
    """
    if x < 0:
        return False
    if x == 0:
        return True  # 0 is a simple power of any integer (0 = 0**int)

    if x < n:
        return False

    # Check if x is a perfect power of n
    # We can iterate from 2 up to sqrt(x) to find the smallest integer k such that n**k == x
    k = 1
    while k * n <= x:
        k += 1

    if k * n == x:
        return True
    else:
        return False

